INSERT INTO public.ministerios (nome, descricao, cor, ordem) VALUES
('Ministério de Pregação', 'A voz que anuncia a Boa Nova, proclamando o Evangelho com unção e poder para tocar corações e transformar vidas.', 'bg-blue-100 text-blue-600', 1),
('Oração por Cura e Libertação', 'Ministério que, pela fé, intercede e proclama a cura e a libertação que vêm de Jesus Cristo para as feridas da alma e do corpo.', 'bg-red-100 text-red-600', 2),
('Ministério para Crianças e Adolescentes', 'Semeando a Palavra de Deus nos corações dos mais novos, guiando-os em seus primeiros passos na fé com alegria e criatividade.', 'bg-yellow-100 text-yellow-600', 3),
('Ministério Jovem', 'A juventude em chamas pelo Espírito Santo! Formando jovens líderes e evangelizadores, ativos na Igreja e no mundo.', 'bg-orange-100 text-orange-600', 4),
('Ministério para as Famílias', 'Levando a experiência do amor de Deus ao coração dos lares, fortalecendo as famílias como igrejas domésticas.', 'bg-green-100 text-green-600', 5),
('Ministério de Intercessão', 'Sustentando a missão da RCC e da Igreja pela oração contínua, em um clamor silencioso e poderoso pelas necessidades de todos.', 'bg-purple-100 text-purple-600', 6),
('Ministério de Formação', 'Aprofundando a fé e o conhecimento da doutrina católica e dos carismas, capacitando líderes e servos para a missão.', 'bg-indigo-100 text-indigo-600', 7),
('Ministério de Música e Artes', 'Louvor que eleva a alma e artes que evangelizam. A serviço da liturgia e da evangelização através do canto, da dança e do teatro.', 'bg-pink-100 text-pink-600', 8),
('Ministério de Comunicação Social', 'Anunciando a Palavra de Deus em todos os meios. Responsável por levar a mensagem da RCC além das fronteiras físicas.', 'bg-cyan-100 text-cyan-600', 9),
('Ministério de Fé e Política', 'Formando cristãos conscientes de seu papel na sociedade, para que atuem nos meios políticos à luz do Evangelho.', 'bg-slate-100 text-slate-600', 10),
('Ministério de Promoção Humana', 'O amor em ação, servindo aos mais necessitados e promovendo a dignidade humana através de obras de misericórdia.', 'bg-emerald-100 text-emerald-600', 11),
('Ministério Universidades Renovadas', 'Levando a cultura de Pentecostes para o ambiente acadêmico, evangelizando estudantes e profissionais.', 'bg-violet-100 text-violet-600', 12);
